            aIngress = RotL64(aSnowLaneC[((aIndex + 28571U)) & S_BLOCK1], 48U) ^ RotL64(aSnowLaneA[((S_BLOCK1 - aIndex + 30511U)) & S_BLOCK1], 13U);
