            //
            aOrbiterI = (aOrbiterI + aOrbiterB) + 0x453A47DA58B66B90ULL;
            aOrbiterK = ((aOrbiterK ^ aOrbiterI) ^ 0xB12D536309B4A72AULL) ^ aPhaseFOrbiterUpdateSaltF[((aIndex + 6U)) & 31];
            aOrbiterK = RotL64((aOrbiterK * 0x2C3F9650C51CD59DULL), 35U);
