            aOrbiterC = ((aOrbiterC + aOrbiterF) + 0x4205130D96A2E824ULL) + aPhaseFOrbiterUpdateSaltA[(((31U - aIndex) + 29U)) & 31];
            aOrbiterI = ((aOrbiterI ^ aOrbiterC) ^ 0x35730B2DBF370DB9ULL) ^ aPhaseFOrbiterUpdateSaltE[(((31U - aIndex) + 7U)) & 31];
