            aOrbiterK = (((aWandererB + RotL64(aCross, 47U)) + RotL64(aCarry, 47U)) + 0x0387DEC41A799E52ULL) + aPhaseEOrbiterAssignSaltA[((aIndex + 13U)) & 31];
