            aIngress = aIngress + (aOrbiterA ^ RotL64(aOrbiterE, 57U));
            aIngress = aIngress + (aOrbiterK ^ RotL64(aOrbiterF, 39U));
            aIngress = aIngress + RotL64(aOrbiterB, 21U);
