            aOrbiterK = RotL64((aOrbiterK * 0xA696CA98B3F4DA6FULL), 51U);
            //
            aOrbiterA = (aOrbiterA + aOrbiterB) + 0x19ED04A793024FE6ULL;
            aOrbiterH = (aOrbiterH ^ aOrbiterA) ^ 0x5056AED177DAB98AULL;
            aOrbiterH = RotL64((aOrbiterH * 0x3DE44F2099A24353ULL), 23U);
