            aPrevious = aIngress;
            //
            aIngress = (RotL64(aExpandLaneC[((aIndex + 30112U)) & S_BLOCK1], 51U) ^ RotL64(aExpandLaneA[((aIndex + 27379U)) & S_BLOCK1], 27U));
            aIngress ^= (RotL64(aInvestLaneB[((aIndex + 27697U)) & S_BLOCK1], 11U) ^ RotL64(aEarthLaneB[((S_BLOCK1 - aIndex + 30340U)) & S_BLOCK1], 40U));
