            //
            aCross = (RotL64(aExpandLaneB[((S_BLOCK1 - aIndex + 30417U)) & S_BLOCK1], 5U) ^ RotL64(aWorkLaneB[((S_BLOCK1 - aIndex + 27517U)) & S_BLOCK1], 13U));
            aCross ^= RotL64(aEarthLaneD[((S_BLOCK1 - aIndex + 28033U)) & S_BLOCK1], 22U);
            aCross = TwistMix64::DiffuseB(aCross);
            //
            aScatter = (RotL64(aIngress, 13U) ^ RotL64(aCross, 39U)) ^ (RotL64(aPrevious, 27U) + RotL64(aCarry, 60U));
