            aOrbiterH = (aWandererI + RotL64(aPrevious, 13U)) + 0xAF32F9515BCA49D8ULL;
            aOrbiterB = ((aWandererJ + RotL64(aCross, 41U)) + 0xA97CD775B14AB872ULL) + aPhaseGOrbiterAssignSaltC[((aIndex + 17U)) & 31];
