            //
            aOrbiterK = ((aOrbiterK + aOrbiterA) + 0xF0F213567791C8E8ULL) + aPhaseGOrbiterUpdateSaltA[(((31U - aIndex) + 19U)) & 31];
            aOrbiterD = (aOrbiterD ^ aOrbiterK) ^ 0x8EDB1A0BD812BAA2ULL;
            aOrbiterD = RotL64((aOrbiterD * 0x0CBE43BD53EF7129ULL), 11U);
