            aOrbiterD = (aOrbiterD + aOrbiterH) + 0x59CF8FEED45E3D18ULL;
            aOrbiterG = ((aOrbiterG ^ aOrbiterD) ^ 0xA0D73CA04B168C3CULL) ^ aPhaseGOrbiterUpdateSaltE[((aIndex + 22U)) & 31];
